app.use((req, res, next) => {
  res.status(404).json({ error: 'Not Found' });
});

// Centralized error handler — must have 4 args
app.use((err, req, res, next) => {
  // Log server-side, don't leak to client
  console.error({ msg: err.message, stack: err.stack, path: req.path });
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal Server Error' : err.message,
  });
});

process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  process.exit(1); // let the supervisor restart
});
```

## 2. No input validation

**Issue:** Even though the current routes don't take user input, the pattern is set by this file. Before any route accepts params/body/query, add validation with a schema library (`zod`, `joi`, or `express-validator`).

**Example for a future `/users/:id`:**
```js
const { z } = require('zod');
const idSchema = z.coerce.number().int().positive();

app.get('/users/:id', (req, res, next) => {
  const parsed = idSchema.safeParse(req.params.id);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  // ... use parsed.data
});
```

Also: `app.use(express.json({ limit: '100kb' }))` — always cap body size to mitigate DoS.

## 3. Security middleware is absent

Add the baseline hardening stack:
```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

app.disable('x-powered-by');            // don't advertise Express
app.use(helmet());                       // sensible security headers
app.use(cors({ origin: process.env.ALLOWED_ORIGIN })); // explicit allowlist
app.use(rateLimit({ windowMs: 60_000, max: 100 }));    // basic abuse throttle
```

## 4. Hardcoded secrets/config

**Issue:** Port `3000` is hardcoded. Real apps will soon have DB URLs, JWT secrets, etc.

```js
const PORT = Number(process.env.PORT) || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```
Never commit secrets; load via env (`dotenv` in dev, secret manager in prod).

## 5. Data leakage in `/users`

**Issue:** `email` is PII. Even in a demo, establish the habit of returning only the fields the caller needs, and requiring auth before exposing user lists.
```js
app.get('/users', requireAuth, (req, res) => {
  res.json(users.map(({ id, name }) => ({ id, name })));
});
```

## 6. Async route safety

When you add async handlers, thrown errors in promises won't reach the error middleware unless you wrap them. Use `express-async-errors` at the top of the file, or a wrapper:
```js
const asyncH = (fn) => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);
app.get('/users', asyncH(async (req, res) => { /* ... */ }));
```

