const app = express();

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));          // cap body size
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Per-IP rate limit on all routes
app.use(rateLimit({
  windowMs: 60_000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
