app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Centralized error handler — must be last, with 4 args
app.use((err, req, res, next) => {
  // Log internally, never leak details to the client
  console.error('[error]', { path: req.path, message: err.message });
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal Server Error'
      : err.message,
  });
});

// Fail fast on unhandled promise rejections
process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
  process.exit(1);
});
```

## 2. No security middleware

**Issue:** Missing standard hardening middleware leaves you exposed to clickjacking, MIME sniffing, MITM downgrade, and unbounded request bodies.

**Suggestion:**
```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

app.disable('x-powered-by');          // Don't advertise Express
app.use(helmet());                     // Sets CSP, HSTS, X-Frame-Options, etc.
app.use(express.json({ limit: '10kb' })); // Cap request body size
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));
```

## 3. No input validation on routes

**Issue:** The current routes don't accept parameters, but as soon as you add `/users/:id` or `POST /users`, you'll need validation. Hand-rolled checks are error-prone — use a schema validator.

**Suggestion (with `zod`):**
```js
