  console.log(`Server running on http://${HOST}:${PORT}`);
});

// Graceful shutdown so in-flight requests complete
for (const signal of ['SIGINT', 'SIGTERM']) {
  process.on(signal, () => {
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref();
  });
}
```

