## Suggested Rewrite

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { z } = require('zod');

const app = express();

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));       // cap body size
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Rate limiting ---
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Env validation ---
const EnvSchema = z.object({
  PORT: z.coerce.number().int().positive().default(3000),
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),
});
const env = EnvSchema.parse(process.env);

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example validated route (for when you add params/body)
const listUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
});

app.get('/users', requireAuth, (req, res, next) => {
  try {
    const { limit } = listUsersQuery.parse(req.query);
    const users = [
      { id: 1, name: 'Alice' },  // no email unless authorized to see it
      { id: 2, name: 'Bob' },
    ].slice(0, limit);
    res.json(users);
  } catch (err) {
    next(err);
  }
});

// --- 404 handler ---
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// --- Error handler (must be last) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, _next) => {
