app.use((err, req, res, next) => {
  console.error(err); // log server-side only
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});

process.on('unhandledRejection', (reason) => console.error('unhandledRejection', reason));
process.on('uncaughtException',  (err)    => { console.error('uncaughtException', err); process.exit(1); });
```

## 2. `app.listen` has no error callback

If port 3000 is already in use, the process throws and dies silently in some supervisors. Capture the server handle and listen for `'error'`:

```js
const server = app.listen(3000, () => console.log('Server running on port 3000'));
server.on('error', (err) => { console.error('Listen error:', err); process.exit(1); });
```

Also, don't call `app.listen` when the module is imported for tests. Guard it:

