  res.status(404).json({ error: 'Not found' });
});

// Centralized error handler (must have 4 args)
app.use((err, req, res, next) => {
  // Log internally, but never send raw error details to the client
  console.error(err);
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal server error' : err.message,
  });
});
```

Also handle process-level failures so the app exits cleanly rather than entering an undefined state:

```js
process.on('unhandledRejection', (reason) => { console.error(reason); process.exit(1); });
process.on('uncaughtException',  (err)    => { console.error(err);    process.exit(1); });
