  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example: validated query params with zod
const listUsersSchema = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(10),
});

app.get('/users', (req, res, next) => {
  try {
    const { limit } = listUsersSchema.parse(req.query);
    const users = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ].slice(0, limit);
    // Do NOT return email unless caller is authorized
    res.json(users);
  } catch (err) {
    if (err instanceof z.ZodError) {
      return res.status(400).json({ error: 'invalid_query', details: err.issues });
    }
    next(err);
  }
});

// --- 404 + error handler ---
app.use((req, res) => res.status(404).json({ error: 'not_found' }));

// eslint-disable-next-line no-unused-vars
app.use((err, req, res, _next) => {
  // Log server-side; don't leak internals
  console.error({ msg: 'unhandled_error', err: err.stack });
  res.status(500).json({ error: 'internal_error' });
});

// --- Bootstrap only when run directly ---
if (require.main === module) {
  const port = Number(process.env.PORT) || 3000;
  const server = app.listen(port, () => {
    console.log(`Server running on port ${port}`);
  });

  const shutdown = (signal) => {
    console.log(`${signal} received, shutting down`);
    server.close(() => process.exit(0));
    // Force-exit after 10s if close hangs
    setTimeout(() => process.exit(1), 10_000).unref();
  };
  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));

  process.on('unhandledRejection', (reason) => {
    console.error({ msg: 'unhandled_rejection', reason });
  });
}

module.exports = app;
```

---

## Summary of Security Improvements

| Concern | Fix |
|---|---|
| Stack trace leakage | Centralized error handler returns opaque `internal_error` |
| Missing headers | `helmet()` + `app.disable('x-powered-by')` |
| DoS via volume | `express-rate-limit` |
| DoS via payload size | `express.json({ limit: '10kb' })` |
| Invalid/malicious input | `zod` schema validation with `.parse()` |
| PII exposure | Drop `email` from `/users` response unless authorized |
| Port/config hardcoded | `process.env.PORT` |
| Test-time side effects | Only listen when `require.main === module` |
| Dropped in-flight requests | `SIGTERM`/`SIGINT` graceful shutdown |
| Silent async crashes | `unhandledRejection` handler |

